import React, { useState } from "react";
import {
  BrowserRouter,
  Routes,
  Route,
  useNavigate,
} from "react-router-dom";

import emailjs from "@emailjs/browser";

import "./App.css";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [error, setError] =
    useState("");

  const validateLogin = () => {
    setError("");

    const savedEmail =
      localStorage.getItem(
        "userEmail"
      );

    const savedPassword =
      localStorage.getItem(
        "userPassword"
      );

    if (
      email === savedEmail &&
      password === savedPassword
    ) {
      emailjs.send(
        "service_gk91tep",
        "template_hqu6lt8",
        {
          user_email: email,
          time:
            new Date().toLocaleString(),
        },
        "omkPXdWy353_kaQ2s"
      );

      alert("Login Successful");
    } else {
      setError(
        "Incorrect email or password"
      );
    }
  };

  return (
    <div className="page">
      <div className="phone-card">
        <div className="top-shape"></div>

        <h1>Welcome</h1>

        <p className="subtitle">
          Sign in to continue
        </p>

        <div className="form">
          <label>Email</label>

          <input
            type="text"
            placeholder="Enter email"
            value={email}
            onChange={(e) =>
              setEmail(
                e.target.value
              )
            }
          />

          <label>Password</label>

          <input
            type="password"
            placeholder="Enter password"
            value={password}
            onChange={(e) =>
              setPassword(
                e.target.value
              )
            }
          />

          {error && (
            <p className="error">
              {error}
            </p>
          )}

          <p
            className="forgot"
            onClick={() =>
              navigate(
                "/forgot-password"
              )
            }
          >
            Forgot Password?
          </p>

          <button
            onClick={validateLogin}
          >
            Sign in
          </button>

          <p className="or">OR</p>

          <p>Connect with</p>

          <div className="socials">
            G | f
          </div>

          <p className="bottom-text">
            Don’t have Account?{" "}
            <span
              onClick={() =>
                navigate(
                  "/register"
                )
              }
            >
              Sign up
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function Register() {
  const navigate = useNavigate();

  const [name, setName] =
    useState("");

  const [email, setEmail] =
    useState("");

  const [phone, setPhone] =
    useState("");

  const [password, setPassword] =
    useState("");

  const [message, setMessage] =
    useState("");

  const registerUser = () => {
    if (
      !name ||
      !email ||
      !phone ||
      !password
    ) {
      setMessage(
        "Please fill all fields"
      );

      return;
    }

    localStorage.setItem(
      "userName",
      name
    );

    localStorage.setItem(
      "userEmail",
      email
    );

    localStorage.setItem(
      "userPhone",
      phone
    );

    localStorage.setItem(
      "userPassword",
      password
    );

    setMessage(
      "Registration Successful!"
    );

    setTimeout(() => {
      navigate("/");
    }, 1500);
  };

  return (
    <div className="page">
      <div className="phone-card">

        <div
          className="back-button"
          onClick={() =>
            navigate("/")
          }
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Create Account</h1>

        <div className="form">
          <label>Name</label>

          <input
            type="text"
            placeholder="Enter name"
            value={name}
            onChange={(e) =>
              setName(
                e.target.value
              )
            }
          />

          <label>Email</label>

          <input
            type="text"
            placeholder="Enter email"
            value={email}
            onChange={(e) =>
              setEmail(
                e.target.value
              )
            }
          />

          <label>Phone</label>

          <input
            type="text"
            placeholder="Enter phone"
            value={phone}
            onChange={(e) =>
              setPhone(
                e.target.value
              )
            }
          />

          <label>Password</label>

          <input
            type="password"
            placeholder="Enter password"
            value={password}
            onChange={(e) =>
              setPassword(
                e.target.value
              )
            }
          />

          {message && (
            <p className="success">
              {message}
            </p>
          )}

          <button
            onClick={registerUser}
          >
            Sign up
          </button>

          <p className="bottom-text">
            Already Have an account?{" "}
            <span
              onClick={() =>
                navigate("/")
              }
            >
              Sign in
            </span>
          </p>
        </div>
      </div>
    </div>
  );
}

function ForgotPassword() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">

        <div
          className="back-button"
          onClick={() =>
            navigate("/")
          }
        >
          ← Back
        </div>

        <div className="top-shape"></div>

        <h1>Reset Password</h1>

        <p className="subtitle">
          Contact admin to reset
          password
        </p>

        <div className="form">
          <button
            onClick={() =>
              navigate("/")
            }
          >
            Back to Login
          </button>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route
          path="/"
          element={<Login />}
        />

        <Route
          path="/register"
          element={<Register />}
        />

        <Route
          path="/forgot-password"
          element={
            <ForgotPassword />
          }
        />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
